importScripts('https://www.gstatic.com/firebasejs/10.10.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.10.0/firebase-messaging-compat.js');

// NOTE: In production builds, this file is regenerated by the Vite plugin
// (firebaseSwPlugin in vite.config.ts) which injects VITE_FIREBASE_* env vars.
// This public/ version is used during local dev only.
const firebaseConfig = {
  apiKey: "REPLACED_AT_BUILD_TIME",
  projectId: "REPLACED_AT_BUILD_TIME",
  messagingSenderId: "REPLACED_AT_BUILD_TIME",
  appId: "REPLACED_AT_BUILD_TIME"
};

try {
  firebase.initializeApp(firebaseConfig);
  const messaging = firebase.messaging();

  messaging.onBackgroundMessage((payload) => {
    console.log('[firebase-messaging-sw.js] Received background message ', payload);
    
    const notificationTitle = payload.notification?.title || payload.data?.title || 'DeskLine';
    const notificationOptions = {
      body: payload.notification?.body || payload.data?.body,
      icon: '/vite.svg'
    };

    self.registration.showNotification(notificationTitle, notificationOptions);
  });
} catch (error) {
  console.log('[firebase-messaging-sw.js] Failed to initialize Firebase:', error);
}
